+
+    // --- Gate 1: Routing Correctness ---
+
+    #[test]
+    fn test_gate1_pass() {
+        // 90% agreement > 85% threshold
+        let mut traces = Vec::new();
+        for _ in 0..9 {
+            traces.push(make_routing_entry(true));
+        }
+        traces.push(make_routing_entry(false));
