+        };
+        format!(
+            "{{\"topk_expert_ids\":{},\"topk_weights\":{},\"teacher_expert_ids\":{},\"teacher_weights\":{},\"agreement\":{}}}",
+            json_usize_array(&self.topk_expert_ids),
